section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/api-contract-first.json",
  "title": "API Contract-First Workflow",
  "type": "object",
  "required": [
    "artefact_id",
    "api_id",
    "spec_path",
    "generator",
    "ci_gates",
    "runtime_validator",
    "consumer_sdks",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "api_id": {
      "type": "string",
      "description": "service id or repo slug",
      "minLength": 1
    },
    "spec_path": {
      "type": "string",
      "description": "path to the OpenAPI 3.1 document (root + sharded refs)",
      "minLength": 1
    },
    "generator": {
      "type": "string",
      "description": "tool used to produce server stubs + SDKs (openapi-generator, oats, oazapfts)",
      "minLength": 1
    },
    "ci_gates": {
      "type": "array",
      "description": "list of CI jobs (spectral-lint, oasdiff-breaking-changes, contract-test)",
      "minItems": 1
    },
    "runtime_validator": {
      "type": "string",
      "description": "library used to validate responses against the spec (pydantic, jsonschema, openapi-core)",
      "minLength": 1
    },
    "consumer_sdks": {
      "type": "array",
      "description": "list of {language, generator-output-path}",
      "minItems": 1
    }
  },
  "additionalProperties": false
}
